+export function observeScrollTop(elementId, dotNetRef) {
+    const el = document.getElementById(elementId);
+    if (!el) return;
+
+    el.addEventListener('scroll', () => {
+        if (el.scrollTop === 0) {
+            dotNetRef.invokeMethodAsync('OnScrolledToTop');
+        }
+    });
+}
+
+export function scrollToBottom(elementId) {
+    const el = document.getElementById(elementId);
+    if (el) {
+        el.scrollTop = el.scrollHeight;
+    }
+}
+
+export function getScrollHeight(elementId) {
+    const el = document.getElementById(elementId);
+    return el ? el.scrollHeight : 0;
+}
+
+export function restoreScrollPosition(elementId, previousScrollHeight) {
+    const el = document.getElementById(elementId);
+    if (el) {
+        el.scrollTop = el.scrollHeight - previousScrollHeight;
+    }
+}
