toolArgs.file_text:
@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="message-list" id="@listId">
    @if (IsLoadingMore)
    {
        <div class="loading-indicator">Loading older messages...</div>
    }

    @foreach (var message in Messages)
    {
        <MessageBubble Message="message"
                       ThreadReplyCount="GetThreadReplyCount(message.Id)"
                       OnOpenThread="() => OnOpenThread.InvokeAsync(message.Id)"
                       OnReact="(emoji) => OnReact.InvokeAsync((message.Id, emoji))" />
    }
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = new();
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private readonly string listId = $"msg-list-{Guid.NewGuid():N}";
    private IJSObjectReference? module;
    private DotNetObjectReference<MessageList>? dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>("import", "./js/chatInterop.js");
            dotNetRef = DotNetObjectReference.Create(this);
            await module.InvokeVoidAsync("observeScrollTop", listId, dotNetRef);
            await module.InvokeVoidAsync("scrollToBottom", listId);
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        if (!IsLoadingMore)
        {
            await OnLoadMore.InvokeAsync();
        }
    }

    public async Task ScrollToBottomAsync()
    {
        if (module is not null)
        {
            await module.InvokeVoidAsync("scrollToBottom", listId);
        }
    }

    private int GetThreadReplyCount(int messageId) =>
        ThreadSummaries.TryGetValue(messageId, out var summary) ? summary.ReplyCount : 0;

    public async ValueTask DisposeAsync()
    {
        dotNetRef?.Dispose();
        if (module is not null)
        {
            await module.DisposeAsync();
        }
    }
}

