arguments.file_text:
.chat-page-layout {
    height: 100vh;
    overflow: hidden;
}

@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="channels"
                    ActiveChannelId="activeChannelId"
                    OnChannelSelected="SelectChannel" />

    <MessageArea @ref="messageAreaRef"
                 ChannelName="@(activeChannel?.Name ?? "")"
                 ChannelDescription="@(activeChannel?.Description ?? "")"
                 Messages="messages"
                 ThreadSummaries="threadSummaries"
                 IsLoadingMore="isLoadingMore"
                 OnLoadMore="LoadMoreMessages"
                 OnOpenThread="OpenThread"
                 OnReact="HandleReaction"
                 OnSendMessage="SendMessage" />

    @if (isThreadOpen)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     Replies="threadReplies"
                     OnClose="CloseThread"
                     OnSendReply="SendThreadReply" />
    }
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = new();
    private Channel? activeChannel;
    private int activeChannelId;
    private bool isThreadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];
    private bool isLoadingMore;
    private const int PageSize = 50;
    private MessageArea? messageAreaRef;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        activeChannelId = channelId;
        activeChannel = channels.FirstOrDefault(c => c.Id == channelId);
        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = [];

        await ChatService.MarkChannelReadAsync(channelId);
        channels = await ChatService.GetChannelsAsync();
        BuildThreadSummaries();
        StateHasChanged();

        await ScrollToBottom();
    }

    private void BuildThreadSummaries()
    {
        threadSummaries.Clear();
        var replyGroups = messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value);

        foreach (var group in replyGroups)
        {
            var replies = group.ToList();
            threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                replies.Count,
                replies.Max(r => r.SentAt));
        }
    }

    private async Task LoadMoreMessages()
    {
        if (isLoadingMore || activeChannel is null) return;
        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannelId, messages.Count, PageSize);
        if (older.Count > 0)
        {
            messages.InsertRange(0, older);
            BuildThreadSummaries();
        }

        isLoadingMore = false;
        StateHasChanged();
    }

    private async Task OpenThread(int messageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == messageId);
        if (threadRootMessage is null) return;

        threadReplies = await ChatService.GetThreadAsync(messageId);
        isThreadOpen = true;
        StateHasChanged();
    }

    private void CloseThread()
    {
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
        messages = await ChatService.GetMessagesAsync(activeChannelId, 0, messages.Count);
        BuildThreadSummaries();
        StateHasChanged();
    }

    private async Task SendMessage(string content)
    {
        if (activeChannel is null) return;
        var newMsg = await ChatService.SendMessageAsync(activeChannelId, content, null);
        messages.Add(newMsg);
        StateHasChanged();
        await ScrollToBottom();
    }

    private async Task SendThreadReply(string content)
    {
        if (threadRootMessage is null || activeChannel is null) return;
        var reply = await ChatService.SendMessageAsync(activeChannelId, content, threadRootMessage.Id);
        threadReplies.Add(reply);
        messages.Add(reply);
        BuildThreadSummaries();
        StateHasChanged();
    }

    private async Task ScrollToBottom()
    {
        if (messageAreaRef is not null)
        {
            await Task.Yield();
            await messageAreaRef.ScrollToBottomAsync();
        }
    }
}

.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}

